package com.example.enterprise.service;

import com.example.enterprise.domain.AppUser;
import com.example.enterprise.domain.UserStatus;
import com.example.enterprise.repository.AppUserRepository;
import jakarta.persistence.EntityNotFoundException;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.Optional;

@Service
public class UserService {

    private final AppUserRepository userRepository;

    public UserService(AppUserRepository userRepository) {
        this.userRepository = userRepository;
    }

    @Transactional
    public AppUser createUser(String username, String email, String passwordHash) {
        if (userRepository.existsByUsername(username)) {
            throw new IllegalArgumentException("Username already exists");
        }
        if (userRepository.existsByEmail(email)) {
            throw new IllegalArgumentException("Email already exists");
        }
        AppUser u = new AppUser();
        u.setUsername(username);
        u.setEmail(email);
        u.setPasswordHash(passwordHash);
        u.setStatus(UserStatus.ACTIVE);
        return userRepository.save(u);
    }

    @Transactional(readOnly = true)
    public AppUser getUser(Long id) {
        return userRepository.findById(id).orElseThrow(() -> new EntityNotFoundException("User not found: " + id));
    }

    @Transactional(readOnly = true)
    public Optional<AppUser> findByUsername(String username) {
        return userRepository.findByUsername(username);
    }

    @Transactional
    public AppUser disableUser(Long id) {
        AppUser u = getUser(id);
        u.setStatus(UserStatus.DISABLED);
        return userRepository.save(u);
    }
}

// src/main/java/com/example/enterprise/service/TransactionService.java
package com.example.enterprise.service;

import com.example.enterprise.domain.*;
import com.example.enterprise.repository.AccountTransactionRepository;
import com.example.enterprise.repository.AppUserRepository;
import jakarta.persistence.EntityNotFoundException;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.math.BigDecimal;
import java.time.Instant;
import java.util.Optional;

@Service
public class TransactionService {

    private final AccountTransactionRepository transactionRepository;
    private final AppUserRepository userRepository;

    public TransactionService(AccountTransactionRepository transactionRepository, AppUserRepository userRepository) {
        this.transactionRepository = transactionRepository;
        this.userRepository = userRepository;
    }

    @Transactional
    public AccountTransaction createTransaction(Long userId,
                                                BigDecimal amount,
                                                String currency,
                                                TransactionType type,
                                                String externalRef,
                                                String description) {
        AppUser user = userRepository.findById(userId)
                .orElseThrow(() -> new EntityNotFoundException("User not found: " + userId));

        if (user.getStatus() != UserStatus.ACTIVE) {
            throw new IllegalStateException("User is not active");
        }

        if (externalRef != null && !externalRef.isBlank()) {
            Optional<AccountTransaction> existing = transactionRepository.findByExternalRef(externalRef);
            if (existing.isPresent()) {
                return existing.get();
            }
        }

        AccountTransaction tx = new AccountTransaction();
        tx.setUser(user);
        tx.setAmount(amount);
        tx.setCurrency(currency);
        tx.setType(type);
        tx.setStatus(TransactionStatus.PENDING);
        tx.setExternalRef(externalRef);
        tx.setDescription(description);

        return transactionRepository.save(tx);
    }

    @Transactional
    public AccountTransaction updateStatus(Long transactionId, TransactionStatus status) {
        AccountTransaction tx = transactionRepository.findById(transactionId)
                .orElseThrow(() -> new EntityNotFoundException("Transaction not found: " + transactionId));
        tx.setStatus(status);
        return transactionRepository.save(tx);
    }

    @Transactional(readOnly = true)
    public Page<AccountTransaction> listUserTransactions(Long userId, Pageable pageable) {
        return transactionRepository.findByUserId(userId, pageable);
    }

    @Transactional
    public int markOldPendingAsFailed(Instant createdBefore) {
        var pending = transactionRepository.findByStatusAndCreatedAtBefore(TransactionStatus.PENDING, createdBefore);
        for (AccountTransaction tx : pending) {
            tx.setStatus(TransactionStatus.FAILED);
        }
        transactionRepository.saveAll(pending);
        return pending.size();
    }
}

