package com.example.enterprise.api;

import com.example.enterprise.api.dto.CreateUserRequest;
import com.example.enterprise.domain.AppUser;
import com.example.enterprise.service.UserService;
import jakarta.validation.Valid;
import org.springframework.http.HttpStatus;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/users")
public class UserController {

    private final UserService userService;

    public UserController(UserService userService) {
        this.userService = userService;
    }

    @PostMapping
    @ResponseStatus(HttpStatus.CREATED)
    public AppUser create(@Valid @RequestBody CreateUserRequest req) {
        return userService.createUser(req.getUsername(), req.getEmail(), req.getPasswordHash());
    }

    @GetMapping("/{id}")
    public AppUser get(@PathVariable Long id) {
        return userService.getUser(id);
    }

    @PostMapping("/{id}/disable")
    public AppUser disable(@PathVariable Long id) {
        return userService.disableUser(id);
    }
}

