package com.example.enterprise.api;

import com.example.enterprise.api.dto.CreateTransactionRequest;
import com.example.enterprise.domain.AccountTransaction;
import com.example.enterprise.domain.TransactionStatus;
import com.example.enterprise.service.TransactionService;
import jakarta.validation.Valid;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.Pageable;
import org.springframework.http.HttpStatus;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/transactions")
public class TransactionController {

    private final TransactionService transactionService;

    public TransactionController(TransactionService transactionService) {
        this.transactionService = transactionService;
    }

    @PostMapping
    @ResponseStatus(HttpStatus.CREATED)
    public AccountTransaction create(@Valid @RequestBody CreateTransactionRequest req) {
        return transactionService.createTransaction(
                req.getUserId(),
                req.getAmount(),
                req.getCurrency(),
                req.getType(),
                req.getExternalRef(),
                req.getDescription()
        );
    }

    @GetMapping("/user/{userId}")
    public Page<AccountTransaction> listByUser(@PathVariable Long userId, Pageable pageable) {
        return transactionService.listUserTransactions(userId, pageable);
    }

    @PostMapping("/{id}/status/{status}")
    public AccountTransaction updateStatus(@PathVariable Long id, @PathVariable TransactionStatus status) {
        return transactionService.updateStatus(id, status);
    }
}